I think you should do the add first:
	nr += *bytes;
	if (abs(nr) < S16_MAX && (!*bytes || abs(nr) < PAGE_SIZE)) {
		*bytes = nr;
	} else {
		*bytes = 0;
		mod_objcg_mlstate(objcg, pgdat, idx, nr);
	}

